"""matplotlib.layout_engine — layout engine stubs."""

class LayoutEngine:
    def __init__(self, **kwargs): pass
    def execute(self, fig): pass
    def set(self, **kwargs): pass
    def get(self): return {}
    def colorbar_gridspec(self): return True

class TightLayoutEngine(LayoutEngine):
    def __init__(self, *, pad=1.08, h_pad=None, w_pad=None, rect=(0, 0, 1, 1)):
        self.pad = pad
        self.h_pad = h_pad
        self.w_pad = w_pad
        self.rect = rect

class ConstrainedLayoutEngine(LayoutEngine):
    def __init__(self, *, h_pad=None, w_pad=None, hspace=None, wspace=None, rect=(0, 0, 1, 1)):
        self.h_pad = h_pad
        self.w_pad = w_pad
        self.hspace = hspace
        self.wspace = wspace
        self.rect = rect

class PlaceHolderLayoutEngine(LayoutEngine):
    pass
